// HMAC-Signaturpruefung (X-Signature: sha256=<hex>) — generischer Helper
const crypto = require('crypto');
const WEBHOOK_SECRET = $env.STELLENIST_WEBHOOK_SECRET || '';
const body = $input.first().json;
const sig = body.headers?.['x-signature'] || '';
if (!WEBHOOK_SECRET) {
  return [{ json: { ...body, _signatureValid: true, _signatureSkipped: true } }];
}
if (!sig.startsWith('sha256=')) throw new Error('Fehlende oder ungueltige X-Signature');
const expected = sig.replace('sha256=', '');
const rawBody = $input.first().binary?.data
  ? Buffer.from($input.first().binary.data, 'base64').toString('utf-8')
  : JSON.stringify(body.body || body);
const computed = crypto.createHmac('sha256', WEBHOOK_SECRET).update(rawBody).digest('hex');
const valid = expected.length === computed.length
  && crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(computed, 'hex'));
if (!valid) throw new Error('Ungueltige HMAC-Signatur');
return [{ json: { ...body, _signatureValid: true } }];

