// HTML-Mail: Neuer Lehrer angelegt
// Format-Tolerant: payload entweder direkt oder unter body.payload (n8n-Webhook)
const data = $input.first().json;
const payload = data.body?.payload || data.payload || data;
const lehrer = payload.lehrer || [];
const count = payload.count || lehrer.length;
const timestamp = data.body?.timestamp || data.timestamp;
const tsFormatted = timestamp
  ? new Date(timestamp).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })
  : new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const schulfarben = {
  GES: { farbe: '#6BAA24', hell: '#E8F5D6' },
  GYM: { farbe: '#FBC900', hell: '#FEF7CC' },
  BK:  { farbe: '#5C82A5', hell: '#DFE8EF' },
  GSH: { farbe: '#E2001A', hell: '#FCE4E8' },
  GSM: { farbe: '#009AC6', hell: '#CCF0FA' },
  GSS: { farbe: '#8B5E3C', hell: '#F0E6DC' },
};

const rows = lehrer.map(l => {
  const sch = schulfarben[l.stammschule] || { farbe: '#575756', hell: '#F0F0F0' };
  return `<tr>
