// HTML-Mail: Hauptdeputat geaendert (gehaltsrelevant)
// Tolerant gegenueber v1- (flat alt/neu) und v2-Payload (perioden[]).
const data = $input.first().json;
const payload = data.body?.payload || data.payload || data;
const aenderungen = payload.aenderungen || [];
const count = payload.count || aenderungen.length;
const timestamp = data.body?.timestamp || data.timestamp;
const tsFormatted = timestamp
  ? new Date(timestamp).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })
  : new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const monatsnamen = ['','Januar','Februar','M\u00e4rz','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];

// Pro Eintrag aggregierte alt/neu-Werte ermitteln (v1: flat; v2: aus erstem/letztem perioden[])
function monatsAggregat(a) {
  if (typeof a.alt === 'number' && typeof a.neu === 'number') {
    return { alt: a.alt, neu: a.neu };
  }
  if (Array.isArray(a.perioden) && a.perioden.length > 0) {
    const first = a.perioden[0];
    const last  = a.perioden[a.perioden.length - 1];
    return { alt: Number(first.alt?.gesamt ?? 0), neu: Number(last.neu?.gesamt ?? 0) };
  }
  return { alt: 0, neu: 0 };
}

const rows = aenderungen.map(a => {
  const { alt, neu } = monatsAggregat(a);
  const diff = neu - alt;
  const diffStr = (diff > 0 ? '+' : '') + diff.toFixed(1);
  const diffColor = diff > 0 ? '#6BAA24' : '#E2001A';
  const monat = monatsnamen[a.monat] || a.monat;
  return `<tr>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:14px;color:#333;">${a.vollname}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:13px;color:#777;text-align:center;">${monat} ${a.jahr}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:14px;text-align:center;color:#575756;">${alt.toFixed(1)}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:14px;text-align:center;font-weight:700;color:#575756;">${neu.toFixed(1)}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:14px;text-align:center;font-weight:700;color:${diffColor};">${diffStr}</td>
  </tr>`;
}).join('');

