// HTML-Mail: Verteilung zwischen Schulen geaendert (NICHT gehaltsrelevant)
// Sync-v2-only Event — Payload hat aenderungen[].perioden[] mit alt/neu pro Schule.
const data = $input.first().json;
const payload = data.body?.payload || data.payload || data;
const aenderungen = payload.aenderungen || [];
const count = payload.count || aenderungen.length;
const timestamp = data.body?.timestamp || data.timestamp;
const tsFormatted = timestamp
  ? new Date(timestamp).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })
  : new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const monatsnamen = ['','Januar','Februar','M\u00e4rz','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];

function summe(a, schule) {
  if (!Array.isArray(a.perioden) || a.perioden.length === 0) return { alt: 0, neu: 0 };
  const first = a.perioden[0];
  const last  = a.perioden[a.perioden.length - 1];
  return {
    alt: Number(first.alt?.[schule] ?? 0),
    neu: Number(last.neu?.[schule] ?? 0),
  };
}
function zelle(s) {
  const diff = s.neu - s.alt;
  if (Math.abs(diff) < 0.001) return `<span style="color:#999;">${s.alt.toFixed(1)}</span>`;
  const arrow = diff > 0 ? '\u25B2' : '\u25BC';
  const color = diff > 0 ? '#6BAA24' : '#E2001A';
  return `<span style="color:#575756;">${s.alt.toFixed(1)}</span> <span style="color:${color};font-weight:700;">${arrow} ${s.neu.toFixed(1)}</span>`;
}

const rows = aenderungen.map(a => {
  const ges = summe(a, 'ges');
  const gym = summe(a, 'gym');
  const bk  = summe(a, 'bk');
  const monat = monatsnamen[a.monat] || a.monat;
  return `<tr>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:14px;color:#333;">${a.vollname}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:13px;color:#777;text-align:center;">${monat} ${a.jahr}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:13px;text-align:center;">${zelle(ges)}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:13px;text-align:center;">${zelle(gym)}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #E5E5E5;font-family:Segoe UI,Arial,sans-serif;font-size:13px;text-align:center;">${zelle(bk)}</td>
  </tr>`;
}).join('');

